function Stars({ count }) {
  const n = Number(count) || 5;
  return (
    <div className="stars" aria-label={`${n} out of 5 stars`}>
      {Array.from({ length: 5 }).map((_, i) => (
        <Star key={i} size={14} fill={i < n ? 'currentColor' : 'none'} strokeWidth={i < n ? 0 : 1.5} />
      ))}
    </div>
  );
}

