function Field({ label, value, onChange, textarea, type = 'text' }) {
  return (
    <label className="admin-field">
      <span>{label}</span>
      {textarea ? (
        <textarea rows={3} value={value || ''} onChange={(e) => onChange(e.target.value)} />
      ) : (
        <input type={type} value={value || ''} onChange={(e) => onChange(e.target.value)} />
      )}
    </label>
  );
}

function ListEditor({ items, onChange, fields, addLabel, emptyItem, titleKey }) {
  const update = (idx, key, val) => onChange(items.map((it, i) => (i === idx ? { ...it, [key]: val } : it)));
  const remove = (idx) => onChange(items.filter((_, i) => i !== idx));
  const add = () => onChange([...items, { ...emptyItem }]);
  return (
    <div className="list-editor">
      {items.map((item, idx) => (
        <div className="list-editor-card" key={idx}>
          <div className="list-editor-card-header">
            <span>{item[titleKey] || `Item ${idx + 1}`}</span>
            <button type="button" className="icon-btn" onClick={() => remove(idx)} aria-label="Remove item">
              <Trash2 size={14} />
            </button>
          </div>
          {fields.map((f) => (
            <label key={f.key} className="admin-field">
              <span>{f.label}</span>
              {f.type === 'textarea' ? (
                <textarea rows={3} value={item[f.key] || ''} onChange={(e) => update(idx, f.key, e.target.value)} />
              ) : f.type === 'select' ? (
                <select value={item[f.key] || ''} onChange={(e) => update(idx, f.key, e.target.value)}>
                  {f.options.map((o) => (
                    <option key={o.value || o} value={o.value || o}>{o.label || o}</option>
                  ))}
                </select>
              ) : (
                <input type="text" value={item[f.key] || ''} onChange={(e) => update(idx, f.key, e.target.value)} />
              )}
            </label>
          ))}
        </div>
      ))}
      <button type="button" className="btn-add" onClick={add}><Plus size={14} /> {addLabel}</button>
    </div>
  );
}

function StringListEditor({ items, onChange, addLabel }) {
  const update = (idx, val) => onChange(items.map((it, i) => (i === idx ? val : it)));
  const remove = (idx) => onChange(items.filter((_, i) => i !== idx));
  const add = () => onChange([...items, '']);
  return (
    <div className="string-list-editor">
      {items.map((item, idx) => (
        <div className="string-list-row" key={idx}>
          <input type="text" value={item} onChange={(e) => update(idx, e.target.value)} />
          <button type="button" className="icon-btn" onClick={() => remove(idx)} aria-label="Remove"><Trash2 size={14} /></button>
        </div>
      ))}
      <button type="button" className="btn-add" onClick={add}><Plus size={14} /> {addLabel}</button>
    </div>
  );
}

